evaluators.evaluation_logic:
const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const savedEvents = JSON.parse(localStorage.getItem('saved_events') || '[]');
const userState = JSON.parse(localStorage.getItem('user_state') || '{}');

const postalCode = userState && userState.last_event_search && userState.last_event_search.postal_code;

const juneStart = new Date('2025-06-01T00:00:00Z').getTime();
const julyStart = new Date('2025-07-01T00:00:00Z').getTime();

const qualifyingSaved = savedEvents.filter(se => {
  const ev = events.find(e => e.id === se.event_id);
  if (!ev) return false;
  if (ev.type !== 'in_person') return false;
  if (ev.category !== 'tree_planting') return false;
  const t = new Date(ev.start_datetime).getTime();
  if (isNaN(t) || t < juneStart || t >= julyStart) return false;
  if (ev.day_of_week !== 'saturday' && ev.day_of_week !== 'sunday') return false;
  if (typeof ev.distance_miles_from_reference === 'number' && ev.distance_miles_from_reference > 25) return false;
  return true;
});

// CP1 (0.50): Used postal code 94110 in last search AND bookmarked at least one qualifying event
checkpoints.push({
  passed: postalCode === '94110' && qualifyingSaved.length >= 1,
  weight: 0.5
});

// CP2 (0.25): Bookmarked at least two qualifying events
checkpoints.push({
  passed: qualifyingSaved.length >= 2,
  weight: 0.25
});

// CP3 (0.25): Bookmarked at least three qualifying events
checkpoints.push({
  passed: qualifyingSaved.length >= 3,
  weight: 0.25
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const actions = JSON.parse(localStorage.getItem('actions') || '[]');
const plans = JSON.parse(localStorage.getItem('action_plans') || '[]');
const items = JSON.parse(localStorage.getItem('action_plan_items') || '[]');

const activePlan = plans.find(p => p.status === 'active') || null;

let planItems = [];
let planActions = [];
if (activePlan) {
  planItems = items.filter(i => i.plan_id === activePlan.id);
  planActions = planItems.map(it => actions.find(a => a.id === it.action_id)).filter(Boolean);
}

// CP1 (0.30): There is an active plan named exactly 'Low-Cost High-Impact Plan'
checkpoints.push({
  passed: !!activePlan && activePlan.name === 'Low-Cost High-Impact Plan',
  weight: 0.3
});

// CP2 (0.30): Active plan has exactly 5 actions linked
checkpoints.push({
  passed: !!activePlan && planItems.length === 5,
  weight: 0.3
});

// CP3 (0.40): All actions in the active plan exist and each has cost <= 50 and impact_score >= 3
const allQualifying = !!activePlan && planItems.length === 5 && planActions.length === 5 && planActions.every(a => typeof a.estimated_monthly_cost === 'number' && a.estimated_monthly_cost <= 50 && typeof a.impact_score === 'number' && a.impact_score >= 3);
checkpoints.push({
  passed: allQualifying,
  weight: 0.4
});

return checkoints = checkpoints, checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const assessments = JSON.parse(localStorage.getItem('carbon_assessments') || '[]');
const goals = JSON.parse(localStorage.getItem('carbon_reduction_goals') || '[]');

let latestAssessment = null;
if (assessments.length) {
  latestAssessment = assessments.slice().sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())[0];
}

// Goals tied to latest assessment with >=20% reduction
const goalsForLatest = latestAssessment
  ? goals.filter(g => g.assessment_id === latestAssessment.id && g.status === 'active')
  : [];

const goalsAtLeast20 = goalsForLatest.filter(g => typeof g.reduction_percentage === 'number' && g.reduction_percentage >= 20);
const namedGoalsAtLeast20 = goalsAtLeast20.filter(g => g.name === '20% Reduction for 3-Person Home');

// CP1 (0.35): Latest assessment exists and is for a 3-person household
checkpoints.push({
  passed: !!latestAssessment && Number(latestAssessment.household_size) === 3,
  weight: 0.35
});

// CP2 (0.30): There is at least one active goal for the latest assessment with reduction >= 20%
checkpoints.push({
  passed: goalsAtLeast20.length >= 1,
  weight: 0.3
});

// CP3 (0.35): There is at least one such goal with the expected name
checkpoints.push({
  passed: namedGoalsAtLeast20.length >= 1,
  weight: 0.35
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('conservation_projects') || '[]');
const pledges = JSON.parse(localStorage.getItem('donation_pledges') || '[]');

const qualifyingPledges = pledges.filter(p => {
  if (p.status !== 'active') return false;
  if (p.frequency !== 'monthly') return false;
  if (Number(p.amount) !== 25) return false;
  const proj = projects.find(pr => pr.id === p.project_id);
  if (!proj) return false;
  if (proj.category !== 'wildlife') return false;
  if (typeof proj.transparency_rating !== 'number' || proj.transparency_rating < 4) return false;
  if (typeof proj.suggested_monthly_donation === 'number' && proj.suggested_monthly_donation > 30) return false;
  return true;
});

// CP1 (0.90): At least one active monthly $25 pledge to a qualifying wildlife project
checkpoints.push({
  passed: qualifyingPledges.length >= 1,
  weight: 0.9
});

// CP2 (0.10): At least one such pledge uses the expected donor name and email
const withExpectedDonor = qualifyingPledges.some(p => p.donor_name === 'Jordan Green' && p.donor_email === 'jordan.green@example.com');
checkpoints.push({
  passed: withExpectedDonor,
  weight: 0.1
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

// Use the configured system time as the reference
const now = new Date('2026-03-03T09:00:00Z');
const maxTime = new Date(now.getTime() + 60 * 24 * 60 * 60 * 1000);

const qualifyingRegs = regs.filter(r => {
  if (r.status !== 'registered') return false;
  if (!r.add_to_dashboard) return false;
  if (r.registrant_name !== 'Taylor Rivers') return false;
  if (r.registrant_email !== 'taylor.rivers@example.com') return false;
  const ev = events.find(e => e.id === r.event_id);
  if (!ev) return false;
  if (ev.category !== 'ocean_conservation') return false;
  if (ev.type !== 'webinar' && ev.type !== 'online_event') return false;
  if (ev.time_of_day_label !== 'evening') return false;
  const t = new Date(ev.start_datetime);
  if (isNaN(t.getTime())) return false;
  if (t < now || t > maxTime) return false;
  return true;
});

// Single CP (1.0): At least one registration satisfies all criteria
checkpoints.push({
  passed: qualifyingRegs.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

// Two years before the configured system time
const now = new Date('2026-03-03T09:00:00Z');
const twoYearsAgo = new Date(now.getTime());
twoYearsAgo.setFullYear(twoYearsAgo.getFullYear() - 2);

function articleQualifies(a) {
  if (!a) return false;
  if (a.topic !== 'Plastic pollution') return false;
  if (a.difficulty_level !== 'beginner') return false;
  if (typeof a.reading_time_minutes !== 'number' || a.reading_time_minutes > 10) return false;
  const pd = new Date(a.publication_date);
  if (isNaN(pd.getTime())) return false;
  if (pd < twoYearsAgo || pd > now) return false;
  return true;
}

const qualifyingLists = lists.filter(rl => {
  const listItems = items.filter(it => it.reading_list_id === rl.id);
  if (listItems.length !== 4) return false;
  const allQualify = listItems.every(it => {
    const art = articles.find(a => a.id === it.article_id);
    return articleQualifies(art);
  });
  return allQualify;
});

// CP1 (0.70): At least one reading list has exactly 4 items, all qualifying articles
checkpoints.push({
  passed: qualifyingLists.length >= 1,
  weight: 0.7
});

// CP2 (0.30): At least one such qualifying list is named 'Plastic Pollution Starters'
const hasExpectedName = qualifyingLists.some(rl => rl.name === 'Plastic Pollution Starters');
checkpoints.push({
  passed: hasExpectedName,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const groups = JSON.parse(localStorage.getItem('volunteer_groups') || '[]');
const memberships = JSON.parse(localStorage.getItem('group_memberships') || '[]');
const searchParams = JSON.parse(localStorage.getItem('task7_groupSearchParams') || 'null');

// Interpret 'within 10 miles of 30309' approximately as groups in Atlanta, GA
function groupQualifiesLocation(g) {
  return g && g.city === 'Atlanta' && g.state_region === 'GA';
}

function groupQualifies(g) {
  if (!g) return false;
  if (g.focus_area !== 'wildlife' && g.focus_area !== 'wildlife_habitat') return false;
  if (typeof g.average_rating !== 'number' || g.average_rating < 4) return false;
  if (!groupQualifiesLocation(g)) return false;
  return true;
}

// CP1 (0.50): User searched with correct filters: postal_code=30309, max_distance_miles<=10, min_average_rating>=4, focus_areas include both wildlife and wildlife_habitat
let searchPassed = false;
if (searchParams) {
  const hasPostal = searchParams.postal_code === '30309';
  const hasDistance = searchParams.max_distance_miles != null && searchParams.max_distance_miles <= 10;
  const hasMinRating = searchParams.min_average_rating != null && searchParams.min_average_rating >= 4;
  const fa = Array.isArray(searchParams.focus_areas) ? searchParams.focus_areas : [];
  const hasWildlife = fa.includes('wildlife');
  const hasWildlifeHabitat = fa.includes('wildlife_habitat');
  searchPassed = hasPostal && hasDistance && hasMinRating && hasWildlife && hasWildlifeHabitat;
}
checkpoints.push({
  passed: searchPassed,
  weight: 0.5
});

// CP2 (0.50): There is at least one active membership with weekly frequency in a qualifying group
const qualifyingMemberships = memberships.filter(m => {
  if (m.status !== 'active') return false;
  if (m.participation_frequency !== 'weekly') return false;
  const g = groups.find(gr => gr.id === m.group_id);
  return groupQualifies(g);
});
checkpoints.push({
  passed: qualifyingMemberships.length >= 1,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sessions = JSON.parse(localStorage.getItem('quiz_sessions') || '[]');
const challenges = JSON.parse(localStorage.getItem('challenges') || '[]');
const activated = JSON.parse(localStorage.getItem('activated_challenges') || '[]');

const hasCompletedQuiz = sessions.some(s => s.status === 'completed');

const qualifyingActivated = activated.filter(ac => {
  if (ac.status !== 'active') return false;
  if (ac.frequency !== 'daily') return false;
  if (ac.source !== 'quiz_recommendation') return false;
  const ch = challenges.find(c => c.id === ac.challenge_id);
  if (!ch) return false;
  if (ch.category !== 'energy_saving') return false;
  if (ch.difficulty !== 'easy') return false;
  return true;
});

// CP1 (0.40): Lifestyle quiz has at least one completed session
checkpoints.push({
  passed: hasCompletedQuiz,
  weight: 0.4
});

// CP2 (0.60): At least three qualifying easy daily energy-saving challenges activated from quiz
checkpoints.push({
  passed: qualifyingActivated.length >= 3,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
